"use strict";(globalThis.webpackChunklearnalgorithms=globalThis.webpackChunklearnalgorithms||[]).push([[2052],{4272(e){e.exports=JSON.parse('{"tag":{"label":"Paradigms","permalink":"/concepts/tags/paradigms","allTagsPath":"/concepts/tags","count":6,"items":[{"id":"state-space-search-and-optimization/branch-and-bound","title":"Branch and Bound","description":"When solving hard combinatorial problems, Backtracking provides an exact solution by executing a systematic Depth-First Search (DFS). However, it does so blindly, relying entirely on hitting an unfeasible boundary before turning around.","permalink":"/concepts/state-space-search-and-optimization/branch-and-bound"},{"id":"algorithm-design-paradigms/brute-force","title":"Brute Force & Exhaustive Search","description":"When facing a novel computational problem, our immediate priority as engineers is not performance, but correctness. Before we can optimize a solution, we must prove that the problem is solvable.","permalink":"/concepts/algorithm-design-paradigms/brute-force"},{"id":"algorithm-design-paradigms/divide-and-conquer","title":"Divide and Conquer","description":"The Divide and Conquer (D&C) paradigm represents one of the most powerful systemic strategies in algorithm design[cite 11]. It fundamentally shifts execution from complex global management to localized resolution and structural combination[cite: 11, 15].","permalink":"/concepts/algorithm-design-paradigms/divide-and-conquer"},{"id":"algorithm-design-paradigms/dynamic-programming","title":"Dynamic Programming","description":"The Dynamic Programming (DP) paradigm stands as one of the most advanced and elegant optimization frameworks in Computer Science. Its core engineering philosophy can be summarized by a classic software axiom: those who cannot remember the past are condemned to repeat it.","permalink":"/concepts/algorithm-design-paradigms/dynamic-programming"},{"id":"algorithm-design-paradigms/greedy-algorithms","title":"Greedy Algorithms","description":"Unlike general programming strategies that explore multiple alternative paths, Greedy Algorithms are designed strictly for optimization problems where the goal is to maximize or minimize a specific objective function.","permalink":"/concepts/algorithm-design-paradigms/greedy-algorithms"},{"id":"state-space-search-and-optimization/backtracking","title":"Introduction to Backtracking","description":"In algorithm design, brute force or exhaustive search should not be used unless absolutely necessary[cite the Magic Square[cite 11]. The objective is to arrange the numbers such that the sum of each individual row, column, and corner-to-corner diagonal matches exactly[cite: 12].","permalink":"/concepts/state-space-search-and-optimization/backtracking"}],"unlisted":false}}')}}]);